import { useState } from "react";
import axios from "axios";

const API_BASE = "http://localhost:8000";

export default function AdminFood() {
  const [foodName, setFoodName] = useState("");
  const [category, setCategory] = useState("");
  const [image, setImage] = useState(null);
  const [preview, setPreview] = useState(null);
  const [loading, setLoading] = useState(false);

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    setImage(file);
    if (file) setPreview(URL.createObjectURL(file));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!foodName || !category || !image) {
      alert("Please fill all fields");
      return;
    }

    const formData = new FormData();
    formData.append("name", foodName);
    formData.append("category", category);
    formData.append("image", image);

    try {
      setLoading(true);
      await axios.post(`${API_BASE}/api/food/`, formData, {
        headers: { "Content-Type": "multipart/form-data" },
      });

      alert("Food item added successfully ✅");
      setFoodName("");
      setCategory("");
      setImage(null);
      setPreview(null);
    } catch (err) {
      alert("Failed to add food ❌");
    } finally {
      setLoading(false);
    }
  };

  return (
    <>
      <style>{`
        .admin-page {
          padding: 40px;
          min-height: 100vh;
          background: #0e0d0d;
          color: #fff;
        }

        .admin-card {
          max-width: 720px;
          margin: auto;
          background: rgba(20, 18, 18, 0.65);
          backdrop-filter: blur(14px);
          border-radius: 22px;
          padding: 36px;
          border: 1px solid rgba(184, 138, 90, 0.25);
        }

        .admin-header {
          margin-bottom: 30px;
        }

        .admin-header h1 {
          font-size: 26px;
          color: #b88a5a;
          margin-bottom: 6px;
        }

        .admin-header p {
          font-size: 14px;
          opacity: 0.8;
        }

        .form-row {
          margin-bottom: 20px;
        }

        .form-row label {
          display: block;
          margin-bottom: 8px;
          font-size: 13px;
          letter-spacing: 0.4px;
        }

        .form-row input,
        .form-row select {
          width: 100%;
          padding: 14px;
          border-radius: 14px;
          border: none;
          background: rgba(255,255,255,0.08);
          color: #fff;
        }

        .form-row input::file-selector-button {
          background: #b88a5a;
          border: none;
          padding: 8px 14px;
          border-radius: 8px;
          margin-right: 12px;
          cursor: pointer;
        }

        .preview-box {
          margin-top: 14px;
          text-align: center;
        }

        .preview-box img {
          width: 160px;
          height: 160px;
          object-fit: cover;
          border-radius: 16px;
          border: 2px solid #b88a5a;
        }

        .submit-btn {
          margin-top: 26px;
          width: 100%;
          padding: 16px;
          border-radius: 16px;
          border: none;
          font-weight: 600;
          background: linear-gradient(135deg, #b88a5a, #e0c097);
          cursor: pointer;
        }

        .submit-btn:disabled {
          opacity: 0.6;
          cursor: not-allowed;
        }
      `}</style>

      <div className="admin-page">
        <div className="admin-card">
          <div className="admin-header">
            <h1>Food Management</h1>
            <p>Add menu items available for guests</p>
          </div>

          <form onSubmit={handleSubmit}>
            <div className="form-row">
              <label>Food Name</label>
              <input
                value={foodName}
                onChange={(e) => setFoodName(e.target.value)}
                placeholder="Eg: Butter Chicken"
              />
            </div>

            <div className="form-row">
              <label>Category</label>
              <select value={category} onChange={(e) => setCategory(e.target.value)}>
                <option value="">Select category</option>
                <option value="bread">Bread</option>
                <option value="drinks">Drinks</option>
                <option value="veg">Veg</option>
                <option value="non-veg">Non Veg</option>
                <option value="dessert">Dessert</option>
              </select>
            </div>

            <div className="form-row">
              <label>Food Image</label>
              <input type="file" accept="image/*" onChange={handleImageChange} />
            </div>

            {preview && (
              <div className="preview-box">
                <img src={preview} alt="Preview" />
              </div>
            )}

            <button className="submit-btn" type="submit" disabled={loading}>
              {loading ? "Adding Food..." : "Add Food Item"}
            </button>
          </form>
        </div>
      </div>
    </>
  );
}
